_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 uv_temp = vUv;
    vUv-= 0.5;
    vUv.y*=-1;
    vUv *= uAspect.xy;

    float rotspeed = 0;
    rotspeed = 0.015*q5 + uTime*0.1;

    float beat = q32;
    vec3 col = 0;

    vec3 lookat = cameralookat;

    float zoom = 1;
    vec3 ro = camerapos;

    if(q15 == 1)
        lookat = camerapos*vec3(1,0,1) + 0.001;

    vec3 F = normalize(lookat-ro); // Forward
    vec3 R = normalize(cross(vec3(0., 1., 0.), F)); //Right
    vec3 U = cross(F, R); //Up

    vec3 C = ro + F*zoom;
    vec3 I = C + vUv.x*R + vUv.y*U;
    vec3 rd = normalize(I-ro);

    vec3 d = RayMarch(ro,rd, MaxSteps);
    vec3 p = ro + rd*d.x;
    vec3 n = GetNormal(p);
    float dif = GetLight(p, n, LightPos, 1, 0.4,  100); //***
    //float dif = 1;
    vec3 Light2Pos = vec3(9*sin(q26),4.03,5*cos(q26*0.581));
    //float dif2 = GetLight(p, Light2Pos, 0.2, 0, 25);
    float dif2 = 0;
    //vec3 pnew = p;
    //pnew = RotZ(pnew, torus1rotspeed);
    vec3 spRefCol = vec3(q1, q2, q3);
    vec3 spRef = specularReflection(p, n, rd, LightPos, 2., 10.) * spRefCol;

    if(d.z == 1) //ground
    {
        //float f = sin(p.x*10)*sin(p.z*10);
        //ret = vec3(0.4,0.3,0.2);
        //ret *= smoothstep(0,0.005,f);
        //float stars = 3*stars(0.01*p.xz, 0);
        //ret *= dif;
        //ret += dif2*vec3(1,0,1);
        vec3 gif = SpaceGif(p.xz);//*dif*2;
        vec3 hive = Hive(p.xz, 2, 100)*dif;
        float hex = smoothstep(-0.7,0.7,sin(HexDist(p.xz)*0.9 - uTime*2 - 0.1*q6));
        ret = gif*0 + 1*lum(hex)*hive;
        //ret.yx += (1-hex)*(1-hive);
        ret += (1-hex)*gif;
        //ret = hive;
        vec2 circle1p = vec2(0,0);
        vec3 circle;
        float circler = 1+3*q27;
        circle = smoothstep(circler, circler+20, length((p.xz+sin(p.zx*100) ) - circle1p));
        ret -= circle*ret;
        circle *= (1-hive);
        ret += circle;
        ret *= dif*1.5;
        ret += dif2*vec3(1.4,0.3,0.3);
        ret += spRef*0.3;
    }
    if(d.z == 2) //torus1
    {
        ret = 1;
        //vec3 torusPosNew = RotY(p + torus1Pos, q26*2 + uTime*0.4);
        vec3 col =  toruscol(RotY(p,q26*1.5), torus1Pos, torus1Size, 0);
        col *= dif;
        ret = col;
        ret = dif*vec3(1.5,1.,0)*col;
        ret += spRef;
        //if(ret.x <= 0 && ret.y <= 0 && ret.z <= 0)
        //    d.z = 1;
    }

    if(d.z == 3) //sphere
    {
     //   float sPosNew = RotX(spherePos, uTime);
        ret = sphereCol(RotZ(RotX(RotY(p,-2.321*q26), PI + 0.8), PI*2 - 0.9), spherePos, sphereRad);
        ret *= dif * (1 + 2*q2);//*vec3(2,0.5,8.5);
        ret += dif2*vec3(1.4,0.3,0.3);
    }

    //ret = applyFog(ret, d.x, rd, normalize(LightPos - vec3(0., 0.3, 0.)), q10);
    ret = applyFog(ret, d.x, q10);

    //float occ = calcOcclusion(p, n);
    //ret = occ;
    //ret = dif;
    //ret = GetNormal(p);
//ret = stars(vUv, uTime);

//    if(sqrt(vUv.x*vUv.x + vUv.y*vUv.y) < 0.001)
//        ret = 1;
//ret = dif2;

  fragColor = ret;
}

